   135→  else if (&S == &APFloat::x87DoubleExtended())
   136→    Ty = Type::getX86_FP80Ty(C);
   137→  else if (&S == &APFloat::IEEEquad())
   138→    Ty = Type::getFP128Ty(C);
   139→  else {
