   330→  default:
   331→    break;
   332→  }
   333→
   334→  IntegerType *&Entry = C.pImpl->IntegerTypes[NumBits];
   335→
   336→  if (!Entry)
   337→    Entry = new (C.pImpl->Alloc) IntegerType(C, NumBits);
   338→
   339→  return Entry;
   340→}
